module counter (
    input clk,
    input sreset,
    input enable,
    output [5:0] q );reg [5:0] unused_q_reg;

always @(posedge clk) begin
    if (sreset)
        unused_q_reg <= 6'b000000;
    else if (enable)
        unused_q_reg <= unused_q_reg + 1;
end

assign q = unused_q_reg;

endmodule
